#include <stdio.h>
#include <string.h>
#include <stdlib.h>
#define MAX_LINE 10000
void reverse_str(char *s){
    int i=0, j=strlen(s)-1;
    while(i<j){
        char tmp=s[i]; s[i]=s[j]; s[j]=tmp;
        i++; j--;
    }
}
int main(){
    char line[MAX_LINE];
    int T;
    if(scanf("%d", &T)!=1) return 0;
    fgets(line, MAX_LINE, stdin); // consume endline after T
    for(int tc=0; tc<T; ++tc){
        if(!fgets(line, MAX_LINE, stdin)) line[0]='\0';
        line[strcspn(line, "\n")] = '\0'; // remove trailing newline
        char *token = strtok(line, " ");
        int first = 1;
        while(token){
            reverse_str(token);
            if(!first) printf(" ");
            printf("%s", token);
            first = 0;
            token = strtok(NULL, " ");
        }
        printf("\n");
    }
    return 0;
}

