import sys

def reverse_strings(strings):
    # Lambda that returns the reversed version of a string
    return list(map(lambda x: x[::-1], strings))

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    T = int(data[0].strip())
    out_lines = []
    for i in range(1, T+1):
        tokens = data[i].split() if i < len(data) else []
        out_lines.append(' '.join(reverse_strings(tokens)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

